    bool topologicalSort( int n, vector<int>& explored, vector<int>& path, 
                          unordered_map<int, vector<int>>& graph, 
                          vector<int>& result) 
    {

        for(int i=0; i<graph[n].size(); i++) {

            int prereq = graph[n][i];

            if ( path[prereq] ) {
                result.clear();
                return false;
